# ---------------------------------------------------------------------------
# PAGE 1 - Input
# ---------------------------------------------------------------------------

def page_input():
    st.title("\U0001f52d Apollo View")
    st.caption("AI-Powered Meeting Intelligence")
    st.markdown("---")

    col1, col2 = st.columns(2)

    with col1:
        plan_name = st.text_input("Plan Name", value="CalPERS", help="e.g. CalPERS, CalSTRS")
        strategy = st.text_input("Strategy", value="Core Fixed Income")
        meeting_type = st.selectbox(
            "Meeting Type",
            ["Annual Review", "RFP Finalist", "First Introduction"],
        )

    with col2:
        meeting_date = st.date_input("Meeting Date", value=date.today())
        manager_name = st.text_input("Manager Name (optional)", value="")
        additional_notes = st.text_area("Additional Notes (optional)", value="", height=100)

    st.markdown("---")

    if st.button("Generate Briefing", type="primary", use_container_width=True):
        if not plan_name.strip():
            st.error("Plan Name is required.")
            return
        if not strategy.strip():
            st.error("Strategy is required.")
            return

        st.session_state["input"] = {
            "plan_name": plan_name.strip(),
            "strategy": strategy.strip(),
            "meeting_type": meeting_type,
            "meeting_date": str(meeting_date),
            "manager_name": manager_name.strip() or None,
            "additional_notes": additional_notes.strip() or None,
        }
        go_to("progress")
        st.rerun()

    render_disclaimer()


# ---------------------------------------------------------------------------
# PAGE 2 - Progress
# ---------------------------------------------------------------------------

STEP_DESCRIPTIONS = {
    "decomposition": "Understanding your meeting and figuring out what to research...",
    "structured": "Pulling fund performance, fees, contract dates, and board info from the database...",
    "rag": "Reading through documents, board minutes, and past meeting notes...",
    "market": "Reviewing the latest market research on fixed income...",
    "news": "Searching for the latest news about this plan and strategy...",
    "synthesis": "Writing your briefing -- this takes a minute, drafting each section...",
}

# Typical seconds per step (used for time-remaining estimate)
STEP_EST_SECONDS = {
    "decomposition": 15,
    "structured": 30,
    "rag": 25,
    "market": 25,
    "news": 10,
    "synthesis": 120,
}

# Ordered step keys matching the pipeline order
STEP_ORDER = ["decomposition", "structured", "rag", "market", "news", "synthesis"]


def _build_step_html(label: str, detail: str) -> str:
    """One completed step as styled HTML."""
    detail_span = f'<span style="color:#666;"> &mdash; {detail}</span>' if detail else ""
    return (
        f'<div style="padding:6px 0; font-size:14px;">'
        f'<span style="color:{ACCENT}; font-weight:600;">{label}</span>'
        f'{detail_span}'
        f'</div>'
    )


def _format_remaining(seconds: float) -> str:
    seconds = max(0, int(seconds))
    if seconds >= 60:
        m, s = divmod(seconds, 60)
        return f"~{m}m {s}s remaining"
    return f"~{seconds}s remaining"


def page_progress():
    from agent_01_query_decomposition import MeetingContext

    inp = st.session_state.get("input")
    if not inp:
        go_to("input")
        st.rerun()
        return

    context = MeetingContext(**inp)

    st.title("\U0001f52d Apollo View")
    st.markdown(
        f"Preparing your briefing for **{context.plan_name}** \u00b7 "
        f"*{context.strategy}* \u00b7 {context.meeting_type}"
    )
    st.markdown("---")

    progress_bar = st.progress(0)
    time_placeholder = st.empty()
    status_placeholder = st.empty()
    log_placeholder = st.empty()

    completed_html_parts: list[str] = []
    total_est = sum(STEP_EST_SECONDS.values())
    elapsed_total = 0.0

    def update_time_remaining():
        remaining = max(0, total_est - elapsed_total)
        time_placeholder.markdown(
            f'<div style="font-size:13px; color:#888; padding:4px 0;">'
            f'{_format_remaining(remaining)}</div>',
            unsafe_allow_html=True,
        )

    def set_status(msg: str):
        status_placeholder.markdown(
            f'<div style="padding:4px 0; font-size:14px; color:#666; '
            f'font-style:italic;">{msg}</div>',
            unsafe_allow_html=True,
        )

    def log_step(label: str, detail: str = ""):
        completed_html_parts.append(_build_step_html(label, detail))
        log_placeholder.markdown(
            "\n".join(completed_html_parts),
            unsafe_allow_html=True,
        )

    try:
        # -- Step 1: Query Decomposition --
        update_time_remaining()
        set_status(STEP_DESCRIPTIONS["decomposition"])
        t0 = time.time()
        decomp_agent = get_decomposition_agent()
        decomposed = decomp_agent.run(context)
        elapsed_total += time.time() - t0
        progress_bar.progress(10)

        n_total = decomposed.total_queries()
        n_struct = len(decomposed.structured_data)
        n_docs = len(decomposed.document_rag)
        n_market = len(decomposed.market_intelligence)
        n_news = len(decomposed.news)
        log_step(
            "Meeting understood",
            f"{n_total} research questions across "
            f"database ({n_struct}), documents ({n_docs}), "
            f"market research ({n_market}), news ({n_news})",
        )

        # -- Step 2: Structured Data --
        update_time_remaining()
        set_status(STEP_DESCRIPTIONS["structured"])
        t0 = time.time()
        struct_agent = get_structured_agent()
        struct_result = struct_agent.run(
            questions=decomposed.structured_data,
            plan_name=context.plan_name,
            manager_name=context.manager_name,
        )
        elapsed_total += time.time() - t0
        progress_bar.progress(25)

        answered = sum(1 for a in struct_result.answers if not a.is_empty())
        unanswered = len(struct_result.answers) - answered
        detail = f"{answered} of {len(struct_result.answers)} database queries returned data"
        if unanswered:
            detail += f" ({unanswered} returned nothing)"
        log_step("Fund data retrieved", detail)

        # -- Step 3: Document RAG --
        update_time_remaining()
        set_status(STEP_DESCRIPTIONS["rag"])
        t0 = time.time()
        rag_agent = get_rag_agent()
        rag_result = rag_agent.run(
            questions=decomposed.document_rag,
            plan_name=context.plan_name,
        )
        elapsed_total += time.time() - t0
        progress_bar.progress(45)

        total_chunks = sum(len(r.chunks) for r in rag_result.question_results)
        n_signals = len(rag_result.topic_shift_signals)
        unique_sources = len({
            c.metadata.get("source_file", "")
            for r in rag_result.question_results
            for c in r.chunks
        })
        detail = f"{total_chunks} passages from {unique_sources} documents"
        if n_signals:
            topics = ", ".join(
                s.topic.replace("_", " ")
                for s in rag_result.topic_shift_signals[:3]
            )
            detail += f" -- board tone shifted on: {topics}"
        log_step("Documents read", detail)

        # -- Step 4: Market Intelligence --
        update_time_remaining()
        set_status(STEP_DESCRIPTIONS["market"])
        t0 = time.time()
        market_agent = get_market_agent()
        market_result = market_agent.run(
            questions=decomposed.market_intelligence,
            strategy=context.strategy,
        )
        elapsed_total += time.time() - t0
        progress_bar.progress(62)

        market_chunks = sum(len(r.chunks) for r in market_result.question_results)
        market_sources = list({
            c.metadata.get("source_file", "").replace(".pdf", "").replace("_", " ").title()
            for r in market_result.question_results
            for c in r.chunks
            if c.metadata.get("source_file")
        })
        log_step(
            "Market research reviewed",
            f"{market_chunks} passages from "
            f"{', '.join(market_sources) if market_sources else 'research documents'}",
        )

        # -- Step 5: News --
        update_time_remaining()
        set_status(STEP_DESCRIPTIONS["news"])
        t0 = time.time()
        news_agent = get_news_agent()
        news_result = news_agent.run(
            questions=decomposed.news,
            plan_name=context.plan_name,
            strategy=context.strategy,
        )
        elapsed_total += time.time() - t0
        progress_bar.progress(75)

        total_items = sum(len(r.items) for r in news_result.question_results)
        mode = (
            news_result.question_results[0].mode_used
            if news_result.question_results else "unknown"
        )
        news_sources = list({
            item.source
            for r in news_result.question_results
            for item in r.items
            if item.source
        })[:4]
        mode_label = "live search" if mode == "live" else "curated sources"
        log_step(
            "News gathered",
            f"{total_items} articles via {mode_label}"
            + (f" -- {', '.join(news_sources)}" if news_sources else ""),
        )

        # -- Step 6: Synthesis --
        update_time_remaining()
        set_status(STEP_DESCRIPTIONS["synthesis"])
        t0 = time.time()
        synth_agent = get_synthesis_agent()
        briefing_result = synth_agent.run(
            meeting_context=context,
            structured_result=struct_result,
            rag_result=rag_result,
            market_result=market_result,
            news_result=news_result,
            report_template=REPORT_TEMPLATE,
            output_path="./briefing_output.pdf",
        )
        elapsed_total += time.time() - t0
        progress_bar.progress(100)

        section_titles = [s.title for s in briefing_result.sections]
        log_step(
            "Briefing written",
            f"{len(section_titles)} sections: {', '.join(section_titles)}",
        )

        # Done: hide time estimate, update status
        time_placeholder.empty()
        status_placeholder.markdown(
            f'<div style="padding:12px 0; font-size:15px; font-weight:600; '
            f'color:{ACCENT};">Your briefing is ready.</div>',
            unsafe_allow_html=True,
        )

        # Store results
        st.session_state["briefing"] = briefing_result

        with open(briefing_result.html_path, "r", encoding="utf-8") as f:
            st.session_state["html_content"] = f.read()

        if briefing_result.pdf_path:
            try:
                with open(briefing_result.pdf_path, "rb") as f:
                    st.session_state["pdf_bytes"] = f.read()
            except Exception:
                st.session_state["pdf_bytes"] = None
        else:
            st.session_state["pdf_bytes"] = None

        render_disclaimer()

        # Auto-navigate to preview
        go_to("preview")
        st.rerun()

    except Exception as e:
        st.session_state["error"] = {
            "message": str(e),
            "traceback": traceback.format_exc(),
        }
        go_to("error")
        st.rerun()


