def render_cover(meeting_context):
    from datetime import date as date_cls
    today = date_cls.today().strftime("%B %d, %Y")

    manager_block = ""
    if meeting_context.manager_name:
        manager_block = (
            f'<div class="cover-item"><label>Manager</label>'
            f'<span>{meeting_context.manager_name}</span></div>'
        )

    # Build as one contiguous string to avoid Streamlit splitting on newlines
    html = (
        PREVIEW_CSS
        + '<div class="briefing-cover">'
        + '<div class="cover-label">Confidential Meeting Preparation</div>'
        + '<div class="cover-title">Intelligence Briefing</div>'
        + f'<div class="cover-subtitle">{meeting_context.plan_name}</div>'
        + '<div class="cover-grid">'
        + f'<div class="cover-item"><label>Strategy</label><span>{meeting_context.strategy}</span></div>'
        + f'<div class="cover-item"><label>Meeting Type</label><span>{meeting_context.meeting_type}</span></div>'
        + f'<div class="cover-item"><label>Meeting Date</label><span>{meeting_context.meeting_date}</span></div>'
        + f'<div class="cover-item"><label>Prepared</label><span>{today}</span></div>'
        + manager_block
        + '</div>'   # close cover-grid
        + '</div>'   # close briefing-cover
    )

    st.markdown(html, unsafe_allow_html=True)


def render_section(section, index: int):
    st.markdown(f'<div id="section-{index}"></div>', unsafe_allow_html=True)
    st.markdown(
        f'<div class="section-heading">{section.title}</div>',
        unsafe_allow_html=True,
    )
    st.markdown(
        f'<div class="section-body">{section.content_html}</div>',
        unsafe_allow_html=True,
    )
    st.markdown(
        f'<div class="section-meta">Sources: {", ".join(section.data_sources_used)}</div>',
        unsafe_allow_html=True,
    )
    st.markdown("---")


def render_insights(insights_html: str):
    st.markdown('<div id="proactive-insights"></div>', unsafe_allow_html=True)
    html = (
        '<div class="insights-box">'
        '<div class="insights-heading">Proactive Insights</div>'
        + insights_html
        + '</div>'
    )
    st.markdown(html, unsafe_allow_html=True)


def page_preview():
    briefing = st.session_state.get("briefing")
    html_content = st.session_state.get("html_content")

    if not briefing or not html_content:
        go_to("input")
        st.rerun()
        return

    # Sidebar: TOC only
    with st.sidebar:
        st.markdown("### \U0001f52d Apollo View")
        st.markdown(f"**{briefing.meeting_context.plan_name}**")
        st.caption(
            f"{briefing.meeting_context.strategy} \u00b7 "
            f"{briefing.meeting_context.meeting_type}"
        )
        st.markdown("---")
        st.markdown("**Table of Contents**")
        for i, section in enumerate(briefing.sections):
            st.markdown(
                f'<a href="#section-{i}" style="text-decoration:none; color:{ACCENT};">'
                f'{i + 1}. {section.title}</a>',
                unsafe_allow_html=True,
            )
        st.markdown(
            f'<a href="#proactive-insights" style="text-decoration:none; color:{ACCENT};">'
            f'Proactive Insights</a>',
            unsafe_allow_html=True,
        )

    # Main content
    render_cover(briefing.meeting_context)

    for i, section in enumerate(briefing.sections):
        render_section(section, i)

    render_insights(briefing.proactive_insights_html)

    # Downloads and reset in main area so they're always visible
    st.markdown("---")
    btn_cols = st.columns(3)
    with btn_cols[0]:
        st.download_button(
            label="Download HTML",
            data=html_content,
            file_name="apollo_view_briefing.html",
            mime="text/html",
            use_container_width=True,
        )
    with btn_cols[1]:
        pdf_bytes = st.session_state.get("pdf_bytes")
        if pdf_bytes:
            st.download_button(
                label="Download PDF",
                data=pdf_bytes,
                file_name="apollo_view_briefing.pdf",
                mime="application/pdf",
                use_container_width=True,
            )
        else:
            st.button("PDF unavailable", disabled=True, use_container_width=True)
    with btn_cols[2]:
        if st.button("New Briefing", use_container_width=True):
            for key in ["input", "briefing", "html_content", "pdf_bytes"]:
                st.session_state.pop(key, None)
            go_to("input")
            st.rerun()

    render_disclaimer()


# ---------------------------------------------------------------------------
# PAGE 4 - Error
# ---------------------------------------------------------------------------

def page_error():
    st.title("\U0001f52d Apollo View")
    st.error("An error occurred while generating your briefing.")

    err = st.session_state.get("error", {})
    st.markdown(f"**Error:** {err.get('message', 'Unknown error')}")

    with st.expander("Full Traceback"):
        st.code(err.get("traceback", "No traceback available"), language="python")

    if st.button("Try Again", type="primary", use_container_width=True):
        st.session_state.pop("error", None)
        go_to("input")
        st.rerun()

    render_disclaimer()


# ---------------------------------------------------------------------------
# Router
# ---------------------------------------------------------------------------

if "page" not in st.session_state:
    st.session_state["page"] = "input"

page = st.session_state["page"]

if page == "input":
    page_input()
elif page == "progress":
    page_progress()
elif page == "preview":
    page_preview()
elif page == "error":
    page_error()
else:
    go_to("input")
    st.rerun()